// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract Vault {
    address public immutable owner;

    constructor(address _owner) {
        owner = _owner;
    }
}

contract VaultFactory {
    function deploy(bytes32 salt, address owner) external returns (address) {
        Vault vault = [[SLOT create2_call]];
        return address(vault);
    }

    function predict(bytes32 salt, address owner) public view returns (address) {
        bytes memory bytecode = abi.encodePacked(
            [[SLOT init_code]],
            abi.encode(owner)
        );
        bytes32 hash = keccak256(
            abi.encodePacked(
                [[SLOT ff_byte]],
                address(this),
                salt,
                keccak256(bytecode)
            )
        );
        return [[SLOT addr_cast]];
    }
}
